def solve(data, criteria):
    if not isinstance(data, list) or not isinstance(criteria, dict):
        raise ValueError("Invalid input types. 'data' should be a list and 'criteria' should be a dictionary.")

    cleaned_data = []
    seen = set()

    for item in data:
        if not isinstance(item, dict):
            raise ValueError("Each item in 'data' should be a dictionary.")

        key = tuple(item.get(k) for k in criteria.keys())
        if key not in seen:
            seen.add(key)
            cleaned_data.append(item)

    return cleaned_data
